// Example domain context mapper for the bill-payment scenario.
//
// The reference receiver is domain-neutral by default: it uses
// `defaultRequestContextMapper`, which simply forwards the inbound A2A data
// part to the PortAuth engine. A real deployment injects its own mapper to
// translate its domain payload into a PortAuth requestContext, apply defaults,
// and coerce/validate fields before evaluation.
//
// This mapper backs the bundled bill-payment demo. Wire it explicitly:
//
//   import { createReferenceReceiverServer } from "portauth-a2a-reference-receiver";
//   import { billPaymentContextMapper } from "portauth-a2a-reference-receiver/examples/bill-payment-mapper.js";
//
//   const { server } = createReferenceReceiverServer({ contextMapper: billPaymentContextMapper });
//
// or via the CLI: A2A_CONTEXT_MAPPER=bill-payment node src/server.js

export function billPaymentContextMapper({ message }) {
  const data = (message.parts || []).find((part) => part?.data !== undefined)?.data || {};
  return {
    action: data.action || "payments:bill_pay",
    resource: data.resource || "urn:bank:utilities/electric",
    requestId: data.requestId || message.taskId || message.messageId,
    claimAmount: coerceFiniteNumber(data.claimAmount, "claimAmount"),
    currency: data.currency || "USD",
    recipientId: data.recipientId,
    geoRegion: data.geoRegion,
  };
}

function coerceFiniteNumber(value, field) {
  const number = Number(value);
  if (!Number.isFinite(number)) {
    throw Object.assign(new Error(`${field} must be a finite number`), { status: 400 });
  }
  return number;
}
